var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"를르슈 비 브리타니아가 명한다.","JPN":"ルルーシュ・ヴィ・ブリタニアが命じる。","ENG":"I, Lelouch vi Britannia, command you.","TWN":"魯路修·Vi·不列顛尼亞在此命令。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"<color=#ff3636>나이엘, 거짓된 학원제를 부정해라!</color>","JPN":"<color=#ff3636>ナイエルよ、偽りの学園祭を否定しろ！</color>","ENG":"<color=#ff3636>Naielle, reject the false festival!</color>","TWN":"<color=#ff3636>奈爾，拒絕假的學園祭！</color>"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_SKILL_START"},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"읏! 무슨 소리야, 나는……!","JPN":"うっ！　何を言ってんの、私は……！","ENG":"Ngh! No way! I...!","TWN":"呃！你在說什麼，我……！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이…… 이딴……!","JPN":"こ、こんな……！","ENG":"D-don't... want...!","TWN":"我，我……才……！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양?","JPN":"ナイエルさん？","ENG":"Naielle?","TWN":"奈爾？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이…… 이딴 재미없는 학원제는 나도 필요 없다구우우우우우우우우우우우!!","JPN":"こ……こんなつまらない学園祭なんか、\\n私だって要らないっつーーーーの！","ENG":"I... don't want anything to do with this lame festivaaaaal!!","TWN":"我才……不需要這種無聊的學園祭呢～～～～！！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"음, 여긴?","JPN":"ここは？","ENG":"Hmm? Where are we?","TWN":"嗯？這裡是？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"공간이 달라졌어? 이곳이 타피르가 말했던 세계와 세계의 틈새인가?","JPN":"空間が変わった！　ここがタピルの言った世界と世界の狭間？","ENG":"The space changed. Is this the gap Tapir talked about?","TWN":"這是跟剛才不同的空間，這裡就是達爾說的，世界與世界之間的縫隙嗎？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저길 보세요, 미나 양!","JPN":"あれを見てください、ミナさん！","ENG":"Look over there, Mina!","TWN":"米娜你看！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"정말이지, 이제야 눈을 뜬 모양이군, 를르슈?","JPN":"まったく。ようやく目を覚ましたか、ルルーシュ。","ENG":"You're finally awake, Lelouch.","TWN":"真是的，你現在才醒過來嗎，魯路修？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"C.C.! 너, 원래대로 돌아온 건가……?","JPN":"C.C.！　お前、元に……","ENG":"C.C.! It's you. Are we back to normal...?","TWN":"C.C.！你，恢復了嗎……？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"정체 모를 녀석에게 너희들이 끌려가 버렸는 걸. 안심하고 틀어박혀 있을 리가 없잖아.","JPN":"お前たちがわけのわからない奴に連れて行かれてしまったんだ。\\nおちおち引き籠ることも出来やしない。","ENG":"You guys were dragged away by some guy. So I couldn't just stay cooped up.","TWN":"來路不明的傢伙把你們帶走，我怎麼可能安心躲起來。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"훗, 그런가. 신세를 졌군.","JPN":"ふっ。そうか。世話をかけたな。","ENG":"Hah, I see. I owe you one.","TWN":"呵，是嗎？那我還得謝謝你囉。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"무슨 소리야? 신세라면 현재진행형으로 지고 있다고, 저길 봐!","JPN":"何を言ってるんだ。現在進行形で世話がかかっている。あれを見ろ。","ENG":"What do you mean? It's not over yet. Look!","TWN":"那還用說？你要謝我的事可多的呢，你看！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>T.A.P.I.R. 프로토콜 일시 침묵.</color>","JPN":"<color=#ff3636>T.A.P.I.R.プロトコル一時沈黙。</color>","ENG":"<color=#ff3636>T.A.P.I.R. Protocol paused.</color>","TWN":"<color=#ff3636>T.A.P.I.R. 協議暫時沉默。</color>"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>프로토콜 재시작까지 약 120초.</color>","JPN":"<color=#ff3636>プロトコル再開始まで約120秒。</color>","ENG":"<color=#ff3636>Restarting Protocol in approximately 120 seconds.</color>","TWN":"<color=#ff3636>距離協議重啟約120秒。</color>"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>119…… 118…… 117…… 116…….</color>","JPN":"<color=#ff3636>119……118……117……116……</color>","ENG":"<color=#ff3636>119... 118... 117... 116...</color>","TWN":"<color=#ff3636>119…… 118…… 117…… 116……</color>"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"천장에 엄청나게 큰 로봇이 매달려 있잖아!?","JPN":"天井にものすごく大きなロボットがぶら下がってる！？","ENG":"There's a huge robot hanging from the ceiling!","TWN":"天花板上掛著巨大的機器人！？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무래도 저 기계가 타피르가 말했던 본체인 것 같군요.","JPN":"どうやらあの機械がタピルの言っていた本体のようですね。","ENG":"That must be the machine Tapir mentioned before.","TWN":"那應該就是達爾的本體。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"저…… 로봇이 타피르 선배라고?","JPN":"あの……ロボットがタピル先輩？","ENG":"That robot is... Tapir?","TWN":"那個……機器人是達爾前輩？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"계속 저 기체를 상대하고 있었어. 너희들이 무의식의 세계에 헤매고 있는 동안 말이야.","JPN":"あれの足止めをしていたんだ。\\nお前たちが閉じ込められている間ずっとな。","ENG":"I was dealing with that machine while you were all lost in the unconscious world.","TWN":"在你們徘徊於潛意識的世界裡時，我一直在對付那個機體。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"저 기체는…….","JPN":"あんなものが……","ENG":"That machine...","TWN":"那個機體是……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 이 느낌……!?","JPN":"待って、この感覚は……！？","ENG":"Hang on, this feeling...!","TWN":"等等，這個感覺是……！？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아카데미에서 느꼈던 그 찌릿찌릿한 느낌의 침식파랑 똑같아!","JPN":"アカデミーで感じたあのビリビリした侵食波と同じだ！","ENG":"It's the same tingling from the Corruption ray I felt at the Academy!","TWN":"這種痠麻感，跟在學院中感受到的侵蝕波一樣！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 저 로봇은 침식체라고 생각하면 되는 건가?","JPN":"じゃあ、あのロボットは侵食体と考えればいいんだよね？","ENG":"So, I just have to treat that robot like a C.O., right?","TWN":"所以只需要把那個機器人當作是侵蝕體來對付嗎？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇지만 저런 형태의 기계형 침식체는 처음 보는군요.","JPN":"ですが、あんな形をした機械型侵食体は初めて見ますね。","ENG":"But, I've never seen a mech-type C.O. like that.","TWN":"不過這種機械型侵蝕體我還是第一次看到。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"묘하게 침착하군. 너희는 저 기체에 대해 뭔가 알고있나? 침식체라고 했던 것 같은데.","JPN":"二人とも妙に落ち着いているが、\\nお前たちはあの機体について何か知っているのか？　侵食体と言ったようだが。","ENG":"You're all oddly calm. Do you know what that thing is? I overheard you calling it a C.O.","TWN":"你們還真是莫名地冷靜。你們知道那個機體是什麼嗎？剛是說侵蝕體？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 우리도 뭐 자세히 알고 있는 건 아닌데…….","JPN":"いや、私たちも詳しいことは知らなくて……","ENG":"Well, we don't know in detail what it is...","TWN":"我們知道的也不多……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아하하…… 이럴 때 상황을 설명해 줄 소대장이 있었으면 좋았을 텐데…….","JPN":"あはは……こんな時に状況を説明してくれる小隊長がいてくれたらよかったのに……","ENG":"Ah hah hah... I wish Commander was here to explain everything...","TWN":"哈哈哈……真希望這種時候有小隊長可以來說明情況……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"C.C. 우리가 잠든 동안, 저 기체와 싸우고 있었다고 했지?","JPN":"C.C.、俺たちが眠っている間にあの機体と戦っていたと言ったな？","ENG":"C.C. You said you were fighting that thing while we were asleep, right?","TWN":"C.C.，你說在我們沉睡的這段時間，你一直在對付那個機體對吧？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"이 공간이나 저 기체에 대해 짐작가는 게 있어?","JPN":"この空間やあの機体について何か知らないのか。","ENG":"Is there anything you've noticed about this place or that robot?","TWN":"那你有發現到什麼嗎？關於這個空間或那個機體的部分？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"알고 있을 리가 없잖아. 그저 이곳이 세계의 <color=#ffd34c>틈새</color>. 원래라면 존재해서는 안 되는 곳이라는 것쯤은 알아.","JPN":"知るわけないだろう。ただ、ここが世界と世界の<color=#ffd34c>狭間</color>であって、\\n本来なら存在しない場所ということぐらいはわかる。","ENG":"I've got nothing. All I know is that this place is a <color=#ffd34c>gap</color> between worlds. A space that shouldn't exist in the first place.","TWN":"當然沒有，我只知道這裡是世界的<color=#ffd34c>縫隙</color>，是原本不該存在的地方。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L10_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"원래라면 존재하지 않는 장소라…… 타피르는 존재해서는 안 되는 이 공간에 우리의 무의식으로 꿈의 세계를 실체화 시켰다고 했어.","JPN":"本来なら存在しない場所。端末のタピルが言っていたことと照らし合わせるなら、\\n本来存在しえない空間に、俺たちの無意識を利用して夢のような空間を実体化させた。","ENG":"A space that shouldn't exist in the first place... Tapir said he created a world with our unconsciousness in a space that shouldn't exist.","TWN":"原本不該存在的地方……達爾說這個空間是根據我們的潛意識而創造出的夢境。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"},"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"즉, 이 공간이 유지되고 있는 건 저 타피르의 본체 때문이 아닐까?","JPN":"つまり、この存在しえない空間を維持しているのは、\\nあのタピル本体だと考えられる。","ENG":"In other words, perhaps this space is held together by Tapir's mainframe?","TWN":"也就是說，這個空間是靠著達爾的本體才得以維持吧？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요, 따라서 그 말은…….","JPN":"と、いうことは？","ENG":"I see, that means...","TWN":"這樣嗎？所以你的意思是……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래, 아마도 타피르 본체를 파괴하면 일시적으로 생성된 이 공간은 유지되지 못하고 우리들은 각자 원래 세계로 돌아갈 수 있을 거야.","JPN":"ああ。あのタピル本体を破壊すれば、\\n二つの世界が融けあっていたこの空間が\\n維持できなくなり、俺たちは存在していた元の世界に戻されるはずだ。","ENG":"Yes. If we destroy Tapir's mainframe, the temporary space will collapse and transport us back to our original worlds.","TWN":"沒錯，只要破壞掉達爾的本體，二個世界融化後而形成的這個空間，便無法再維持下去，我們也就能夠各自回到原本的世界。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇지만…… 저렇게 높은 곳에 있는데 어떻게 공격하지?","JPN":"でも……あんな高い所にいるのにどうやって攻撃するの？","ENG":"But... how are we supposed to attack something that's so high up?","TWN":"可是……本體在那麼高的地方，是要怎麼攻擊？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"걱정할 필요 없어. 여기서부터는 <color=#ffd34c>그것</color>을 쓸 수 있을 테니까.","JPN":"心配いらないさ。ここなら俺たちはあれが使えるはずだ。","ENG":"Don't worry about that. From here on out, we can use <color=#ffd34c>this</color>.","TWN":"不用擔心，我們可以使用<color=#ffd34c>那個</color>。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그것이라고……?","JPN":"あれ……？","ENG":"Use what...?","TWN":"哪個……？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"응? 무슨 소리지?","JPN":"あれ？　何の音？","ENG":"Hmm? Do you hear that?","TWN":"嗯？這是什麼聲音？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"가자! 홍련! 지금부터는 우리가 실력을 발휘할 때야!","JPN":"行くよ！　紅蓮！　ここからは、私たちの本領発揮よ！","ENG":"Let's go, Guren! It's time we showed off our skills!","TWN":"走吧！紅蓮！現在換我們發揮實力了！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEITEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저 목소리는…… 카렌이야? 카렌이 저 붉은 로봇에?","JPN":"あの声は……カレンなの？　カレンがあの赤いロボットに？","ENG":"That voice... Is that Kallen? Is she inside that red robot?","TWN":"那個聲音是…… 卡蓮嗎？卡蓮在那個紅色機器人裡？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEITEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래. 홍련에 탑승한 카렌은 세계 최강의 에이스 파일럿이지.","JPN":"ああ。世界最強のエース。それが紅蓮を駆る紅月カレンだ。","ENG":"Correct. Kallen is the world's strongest ace pilot when she's riding Guren.","TWN":"沒錯，駕駛紅蓮的卡蓮是世界第一的駕駛員。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_PRIDE"},"C":{"char_id":"SEITEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"눈을 뜨는게 늦었네, 카렌.","JPN":"随分と遅いお目覚めだな、カレン。","ENG":"Looks like it took you a while to wake up, Kallen.","TWN":"你現在才醒過來啊，卡蓮。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"C":{"char_id":"SEITEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"C.C., 너…… 원래대로……. 흥, 지금 그 말 그대로 되돌려주도록 할까.","JPN":"C.C.……あんた、元に……フン。その言葉、そっくりそのまま返すわ。","ENG":"C.C., you're... back... Hmph! I can say the same about you.","TWN":"C.C.，你……恢復……哼，我要把那句話原封不動地還給你嗎？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"C":{"char_id":"SEITEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"후후, 그거 미안하게 됐네. 그래도 여기서는 꽤 노력했으니까 지금은 너그럽게 봐줘.","JPN":"くくっ。それはすまなかったな。\\nしかし、ここで働いていた分、大目にみてくれ。","ENG":"Ha ha, sorry about that. But I tried my best here, so go easy on me.","TWN":"呵呵，算我不對，看在我在這裡這麼努力的份上，你就大人不記小人過吧。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_PRIDE"},"C":{"char_id":"SEITEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"그보다 이 기체로는 화력이 부족해. 하지만 너와 그 홍련이라면…….","JPN":"それよりも私の機体では、火力が足りない。\\nだが、お前と紅蓮なら……","ENG":"Besides that, this one lacks firepower. But if it's you and Guren...","TWN":"現在問題是光靠這個機體的火力不夠，但若是你和紅蓮……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"C":{"char_id":"SEITEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"카렌! 타피르의 본체를 바닥으로 떨어트려 버려라!","JPN":"カレン！　タピル本体を地上に叩き落せ！","ENG":"Kallen! Drop Tapir's mainframe to the floor!","TWN":"卡蓮！將達爾的本體擊落至地面！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"좋아, 나와 홍련의 힘을 보여주겠어!","JPN":"了解！　私と紅蓮の力、見せてあげる！","ENG":"Roger. I'll show you what Guren and I can do!","TWN":"沒問題，看我和紅蓮的厲害！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>외부로부터 적성개체를 포착. T.A.P.I.R. 프로토콜 일시 중단.</color>","JPN":"<color=#ff3636>外部から敵性個体を捕捉。T.A.P.I.R.プロトコル一時中止。</color>","ENG":"<color=#ff3636>Hostile unit detected. T.A.P.I.R. Protocol temporarily canceled.</color>","TWN":"<color=#ff3636>從外部捕捉到適性個體。T.A.P.I.R. 協議暫停。</color>"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>적성개체 배제를 위하여 한시적 섬멸모드, 180초 가동합니다.</color>","JPN":"<color=#ff3636>敵性個体排除のため、一時的殲滅モード、180秒間稼動します。</color>","ENG":"<color=#ff3636>Activating annihilation mode for 180 seconds to eliminate hostile unit.</color>","TWN":"<color=#ff3636>暫時啟動殲滅模式180秒，目標排除適性個體。</color>"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"흥, 그런 어설픈 공격 맞을 리 없잖아! 이거라도 먹어라!","JPN":"はっ！　そんな攻撃、当たらないね。これでも食らいな！","ENG":"Hmph, your lousy attacks can't hit me! Take this!","TWN":"哼，那種三腳貓的攻擊怎麼可能打得到我，吃我一擊！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"모두 잘 들어! 홍련의 일격에 적 기체는 추락했다!","JPN":"よし、みんな聞け！　紅蓮の一撃によって敵の機体は墜落した！","ENG":"Attention, all! Guren's strike has taken down the enemy!","TWN":"大家聽著！紅蓮已經將敵人的本體擊落！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"이걸로 조건은 클리어 되었어!","JPN":"これで条件はクリアだ！","ENG":"All tasks at hand have been cleared.","TWN":"這樣一來就滿足所有條件！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"이대로 타피르의 본체를 파괴하고, 빼앗긴 우리의 내일을 되찾는 거다!!","JPN":"このまま敵タピル本体を破壊し、奪われた俺たちの明日を取り戻す！！","ENG":"Destroy Tapir's mainframe and take back our future!!","TWN":"破壞達爾的本體，找回我們被奪走的明天吧！！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};